starterCode.css:
body {
  margin: 0;
  min-height: 100vh;
  display: grid;
  place-items: center;
  background: #f7f2ea;
  font-family: Georgia, serif;
}

.texto {
  width: min(760px, calc(100vw - 32px));
  padding: 24px;
  border-radius: 18px;
  background: white;
  box-shadow: 0 14px 40px rgba(0, 0, 0, 0.08);
}

targetCode.css:
body {
  margin: 0;
  min-height: 100vh;
  display: grid;
  place-items: center;
  background: #f7f2ea;
  font-family: Georgia, serif;
}

.texto {
  width: min(760px, calc(100vw - 32px));
  padding: 24px;
  border-radius: 18px;
  background: white;
  box-shadow: 0 14px 40px rgba(0, 0, 0, 0.08);
  column-count: 3;
  column-gap: 24px;
  column-rule: 1px solid #d6d3d1;
}
